func (h *CategoryHandler) GetCategory(w http.ResponseWriter, r *http.Request) {
	startTime := time.Now()
	logger := slog.With(
		"method", r.Method,
		"path", r.URL.Path,
		"remoteAddr", r.RemoteAddr,
	)

	idStr := r.PathValue("id")
	if idStr == "" {
		logger.Error("category ID is required")
		http.Error(w, "category ID is required", http.StatusBadRequest)
		return
	}

	categoryID, err := strconv.ParseInt(idStr, 10, 32)
	if err != nil {
		logger.Error("failed to parse category ID", "error", err)
		http.Error(w, "invalid category ID", http.StatusBadRequest)
		return
	}

	category, err := h.categoryService.GetCategory(r.Context(), int32(categoryID))
	if err != nil {
		logger.Error("failed to get category", "error", err)
		http.Error(w, "failed to get category", http.StatusInternalServerError)
		return
	}

	categoryResponse, err := newCategoryResponse(category)
	if err != nil {
		logger.Error("failed to create category response", "error", err)
		http.Error(w, "internal server error", http.StatusInternalServerError)
		return
	}

	w.Header().Set("Content-Type", "application/json")
	if err := json.NewEncoder(w).Encode(categoryResponse); err != nil {
		logger.Error("failed to encode response", "error", err)
		http.Error(w, "failed to encode response", http.StatusInternalServerError)
		return
	}

	logger.Info("category retrieved successfully",
		"responseTime", time.Since(startTime),
	)
}

# Extracting Reusable Functionality

To extract the common pattern of logging request start/end times and standardizing request handling, I'll create middleware and helper functions. Here's how to refactor this functionality:

## 1. Create a RequestLogger Middleware

```go
package middleware

import (
	"log/slog"
	"net/http"
	"time"
)

// RequestLogger creates middleware that logs request details and timing
func RequestLogger(next http.Handler) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		startTime := time.Now()
		logger := slog.With(
			"method", r.Method,
			"path", r.URL.Path,
			"remoteAddr", r.RemoteAddr,
		)

		// Store logger in request context
		ctx := r.Context()
		ctx = context.WithValue(ctx, "logger", logger)
		r = r.WithContext(ctx)

		// Call the next handler
		next.ServeHTTP(w, r)

		// Log response time after handler completes
		logger.Info("request completed", 
			"responseTime", time.Since(startTime),
		)
	})
}
```

## 2. Create Handler Helpers

```go
package handlers

import (
	"encoding/json"
	"log/slog"
	"net/http"
	"strconv"
)

// GetLogger retrieves the logger from request context
func GetLogger(r *http.Request) *slog.Logger {
	logger, ok := r.Context().Value("logger").(*slog.Logger)
	if !ok {
		// Fallback if logger not in context
		return slog.With(
			"method", r.Method,
			"path", r.URL.Path,
			"remoteAddr", r.RemoteAddr,
		)
	}
	return logger
}

// RespondJSON sends a JSON response with proper headers
func RespondJSON(w http.ResponseWriter, r *http.Request, data interface{}) {
	logger := GetLogger(r)
	w.Header().Set("Content-Type", "application/json")

	if err := json.NewEncoder(w).Encode(data); err != nil {
		logger.Error("failed to encode response", "error", err)
		http.Error(w, "failed to encode response", http.StatusInternalServerError)
		return
	}
}

// RespondError logs and sends an error response
func RespondError(w http.ResponseWriter, r *http.Request, message string, statusCode int, err error) {
	logger := GetLogger(r)
	logger.Error(message, "error", err, "statusCode", statusCode)
	http.Error(w, message, statusCode)
}

// ParseIDParam parses an ID from URL path parameter
func ParseIDParam(w http.ResponseWriter, r *http.Request, paramName string) (int64, bool) {
	logger := GetLogger(r)
	idStr := r.PathValue(paramName)
	if idStr == "" {
		RespondError(w, r, paramName+" is required", http.StatusBadRequest, nil)
		return 0, false
	}

	id, err := strconv.ParseInt(idStr, 10, 64)
	if err != nil {
		RespondError(w, r, "invalid "+paramName, http.StatusBadRequest, err)
		return 0, false
	}

	return id, true
}
```

## 3. Refactor the Original Handler

```go
func (h *CategoryHandler) GetCategory(w http.ResponseWriter, r *http.Request) {
	logger := handlers.GetLogger(r)

	categoryID, ok := handlers.ParseIDParam(w, r, "id")
	if !ok {
		return
	}

	category, err := h.categoryService.GetCategory(r.Context(), int32(categoryID))
	if err != nil {
		handlers.RespondError(w, r, "failed to get category", http.StatusInternalServerError, err)
		return
	}

	categoryResponse, err := newCategoryResponse(category)
	if err != nil {
		handlers.RespondError(w, r, "internal server error", http.StatusInternalServerError, err)
		return
	}

	handlers.RespondJSON(w, r, categoryResponse)
	logger.Info("category retrieved successfully")
}
```

## 4. Register the Middleware

```go
// In main.go or where you set up your routes
import "yourproject/middleware"

func setupRoutes() {
    // Create router
    mux := http.NewServeMux()

    // Add handlers with middleware
    categoryHandler := &CategoryHandler{categoryService: categoryService}
    mux.Handle("GET /categories/{id}", middleware.RequestLogger(http.HandlerFunc(categoryHandler.GetCategory)))

    // ... other routes

    return mux
}
```

This refactoring:
1. Extracts the logging logic into middleware
2. Provides helper functions for common handler operations
3. Makes your handler code more concise and focused on business logic
4. Maintains consistent error handling and response formatting

You can further extend this pattern with additional middleware for authentication, rate limiting, etc.
